-- One-time sync: push course_image_url (R2 cover URLs) from local dev to prod.
--
-- R2 is shared between dev and prod, so the URLs are already valid live;
-- only the EAV pointer rows need to land in the prod DB. We key on SKU so
-- entity_id drift between environments is irrelevant.
--
-- attribute_id is resolved at runtime via @aid (do NOT hard-code 203 — the
-- value may differ in prod).
--
-- Idempotent: ON DUPLICATE KEY UPDATE rewrites the URL if a different one
-- already exists for that product. Safe to re-run.

SET @aid := (SELECT attribute_id FROM eav_attribute WHERE attribute_code='course_image_url' LIMIT 1);

INSERT INTO catalog_product_entity_varchar (entity_type_id, attribute_id, store_id, entity_id, value)
SELECT 4, @aid, 0, cpe.entity_id, t.url
FROM catalog_product_entity cpe
JOIN (
  SELECT 'C009' sku, 'https://pub-77c0dec029944b0386e40673ce81081f.r2.dev/course-covers/C009-20260523-093428.png' url
  UNION ALL SELECT 'C012', 'https://pub-77c0dec029944b0386e40673ce81081f.r2.dev/course-covers/C012-20260523-093430.png'
  UNION ALL SELECT 'C013', 'https://pub-77c0dec029944b0386e40673ce81081f.r2.dev/course-covers/C013-20260523-093430.png'
  UNION ALL SELECT 'C015', 'https://pub-77c0dec029944b0386e40673ce81081f.r2.dev/course-covers/C015-20260523-093431.png'
